import random

def augment_text(text, synonym_map, p=0.1):
    words = text.split()
    out = []
    for w in words:
        if random.random() < p and w.lower() in synonym_map:
            out.append(random.choice(synonym_map[w.lower()]))
        else:
            out.append(w)
    return " ".join(out)

# synonym_map built offline from WordNet or a thesaurus
augmented = augment_text("battery life is excellent", {"excellent": ["great", "superb"]})
